const API_BASE="/peace_seafood/api";const apiClient=axios.create({baseURL:API_BASE,timeout:3e4,headers:{"Content-Type":"application/json","Accept":"application/json"}});apiClient.interceptors.request.use(config=>{const token=localStorage.getItem("token");if(token){config.headers["Authorization"]="Bearer "+token}return config},error=>Promise.reject(error));apiClient.interceptors.response.use(response=>response,error=>{var _a;if(((_a=error.response)==null?void 0:_a.status)===401){localStorage.removeItem("token");localStorage.removeItem("user");window.location.href="/peace_seafood/login"}return Promise.reject(error)});window.apiClient=apiClient;function formatRupiah(amount){return"Rp "+(parseFloat(amount)||0).toLocaleString("id-ID",{minimumFractionDigits:0})}function formatDate(dateStr){if(!dateStr)return"-";return new Date(dateStr).toLocaleDateString("id-ID",{day:"numeric",month:"long",year:"numeric"})}function formatDateShort(dateStr){if(!dateStr)return"-";return new Date(dateStr).toLocaleDateString("id-ID")}function showToast(type,title,message){if(window.iziToast){iziToast[type]({title,message,position:"topRight",timeout:3e3})}}window.formatRupiah=formatRupiah;window.formatDate=formatDate;window.formatDateShort=formatDateShort;window.showToast=showToast;;const Utils=(()=>{function formatCurrency(amount){return new Intl.NumberFormat("id-ID",{style:"currency",currency:"IDR",minimumFractionDigits:0}).format(amount!=null?amount:0)}function formatNumber(num){return new Intl.NumberFormat("id-ID").format(num!=null?num:0)}function formatDate2(dateStr,options={}){if(!dateStr)return"-";const defaults={day:"2-digit",month:"short",year:"numeric"};return new Date(dateStr).toLocaleDateString("id-ID",{...defaults,...options})}function formatDateTime(dateStr){if(!dateStr)return"-";return new Date(dateStr).toLocaleString("id-ID")}function showToast2(message,type="info"){const container=document.getElementById("toast-container")||(()=>{const el=document.createElement("div");el.id="toast-container";el.className="toast-container";document.body.appendChild(el);return el})();const colorMap={success:"bg-success",error:"bg-danger",warning:"bg-warning",info:"bg-info"};const toast=document.createElement("div");toast.className=`toast show text-white ${colorMap[type]||"bg-info"}`;toast.innerHTML=`
      <div class="toast-body d-flex justify-content-between align-items-center">
        <span>${message}</span>
        <button type="button" class="btn-close btn-close-white ms-2" onclick="this.closest('.toast').remove()"></button>
      </div>
    `;container.appendChild(toast);setTimeout(()=>toast.remove(),4e3)}function confirm(message){return window.confirm(message)}function debounce(fn,delay=300){let timer;return(...args)=>{clearTimeout(timer);timer=setTimeout(()=>fn(...args),delay)}}function toggleDarkMode(){const current=document.documentElement.getAttribute("data-theme");const next=current==="dark"?"light":"dark";document.documentElement.setAttribute("data-theme",next);localStorage.setItem("theme",next)}function applySavedTheme(){const saved=localStorage.getItem("theme")||"light";document.documentElement.setAttribute("data-theme",saved)}async function showNotaDetail(id){var _a;if(!id)return;if(window.penjualanPageInstance&&typeof window.penjualanPageInstance.showDetail==="function"){return window.penjualanPageInstance.showDetail(id)}try{const token=localStorage.getItem("token");const res=await axios.get("/peace_seafood/api/penjualan/"+id,{headers:{Authorization:"Bearer "+token}});const detail=(_a=res.data)==null?void 0:_a.data;if(!detail)throw new Error("No data");const overlay=document.createElement("div");overlay.className="modal-overlay";overlay.style="position:fixed;inset:0;background:rgba(0,0,0,0.5);display:flex;align-items:center;justify-content:center;z-index:9999";const box=document.createElement("div");box.className="modal-box";box.style="background:var(--bg-light);color:var(--text-primary);max-width:800px;padding:1rem;border-radius:0.5rem;max-height:80vh;overflow:auto";box.innerHTML=`
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:0.5rem">
          <h3 style="margin:0">Nota: ${detail.no_nota||""}</h3>
          <button aria-label="close" style="background:transparent;border:0;font-size:1.2rem;cursor:pointer">×</button>
        </div>
        <div style="display:flex;gap:1rem;margin-bottom:0.75rem">
          <div style="flex:1">
            <div><small style="color:var(--text-secondary)">Pembeli</small><div>${detail.nama_pembeli||"Umum"}</div></div>
            <div><small style="color:var(--text-secondary)">Tanggal</small><div>${new Date(detail.tanggal_nota||"").toLocaleDateString("id-ID")||"-"}</div></div>
          </div>
          <div style="text-align:right">
            <div><small style="color:var(--text-secondary)">Total</small><div style="color:var(--color-primary)">${new Intl.NumberFormat("id-ID",{style:"currency",currency:"IDR",minimumFractionDigits:0}).format(detail.total||0)}</div></div>
          </div>
        </div>
        <div style="overflow:auto">
          <table style="width:100%;border-collapse:collapse">
            <thead><tr><th style="text-align:left;padding:6px;border-bottom:1px solid var(--border-color)">Produk</th><th style="text-align:right;padding:6px;border-bottom:1px solid var(--border-color)">Qty</th><th style="text-align:right;padding:6px;border-bottom:1px solid var(--border-color)">Harga</th></tr></thead>
            <tbody>
              ${(detail.items||[]).map(it=>`<tr><td style="padding:6px;border-bottom:1px solid var(--border-color)">${it.nama_produk}</td><td style="padding:6px;border-bottom:1px solid var(--border-color);text-align:right">${parseFloat(it.qty)} ${it.satuan||"kg"}</td><td style="padding:6px;border-bottom:1px solid var(--border-color);text-align:right">${new Intl.NumberFormat("id-ID",{style:"currency",currency:"IDR",minimumFractionDigits:0}).format(it.harga_jual||0)}</td></tr>`).join("")}
            </tbody>
          </table>
        </div>
      `;overlay.appendChild(box);document.body.appendChild(overlay);overlay.addEventListener("click",e=>{if(e.target===overlay)overlay.remove()});box.querySelector('button[aria-label="close"]').addEventListener("click",()=>overlay.remove());if(window.lucide)window.lucide.createIcons()}catch(e){window.location.href="/peace_seafood/penjualan"}}return{formatCurrency,formatNumber,formatDate:formatDate2,formatDateTime,showToast:showToast2,confirm,debounce,toggleDarkMode,applySavedTheme,showNotaDetail}})();document.addEventListener("DOMContentLoaded",()=>Utils.applySavedTheme());window.showNotaDetail=Utils.showNotaDetail;;const Auth=(()=>{const TOKEN_KEY="token";const USER_KEY="user";async function login(username,password){const data=await ApiClient.post("/auth/login",{email:username,password});if(data.token){localStorage.setItem(TOKEN_KEY,data.token);localStorage.setItem(USER_KEY,JSON.stringify(data.user))}return data}async function logout(){try{await ApiClient.post("/auth/logout")}finally{localStorage.removeItem(TOKEN_KEY);localStorage.removeItem(USER_KEY);window.location.href="/peace_seafood/login"}}function getUser(){const user=localStorage.getItem(USER_KEY);return user?JSON.parse(user):null}function getToken(){return localStorage.getItem(TOKEN_KEY)}function isAuthenticated(){return!!getToken()}function hasRole(role){const user=getUser();return user&&user.role===role}function init(){if(!isAuthenticated()&&!window.location.pathname.includes("/login")){window.location.href="/peace_seafood/login"}}return{login,logout,getUser,getToken,isAuthenticated,hasRole,init}})();document.addEventListener("DOMContentLoaded",()=>Auth.init());
